export { default as STooltip } from './tooltip.vue';

export type * from '@soybeanjs/headless/tooltip';
export type * from './types';

import type {
  TooltipCompactEmits,
  TooltipCompactProps,
  TooltipCompactSlots,
  TooltipUi
} from '@soybeanjs/headless/tooltip';
import type { ClassValue } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the Tooltip component.
 */
export interface TooltipProps extends TooltipCompactProps {
  /**
   * class of popup
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<TooltipUi>;
}

/**
 * Events for the Tooltip component.
 */
export type TooltipEmits = TooltipCompactEmits;

/**
 * Slots for the Tooltip component.
 */
export type TooltipSlots = TooltipCompactSlots;

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const tooltipVariants = scv({
  slots: {
    positioner: 'w-max',
    popup: [
      `w-auto rounded-md border bg-popover text-popover-foreground shadow-md outline-none z-50 will-change-transform`,
      `animate-in fade-in-0 zoom-in-95`,
      `data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95`,
      `data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2`
    ],
    arrow: 'w-1em h-0.5em fill-popover stroke-border'
  },
  variants: {
    size: {
      xs: {
        popup: 'px-2 py-1 text-2xs',
        arrow: 'text-3xs'
      },
      sm: {
        popup: 'px-2.5 py-1.25 text-xs',
        arrow: 'text-2xs'
      },
      md: {
        popup: 'px-3 py-1.5 text-sm',
        arrow: 'text-xs'
      },
      lg: {
        popup: 'px-3.5 py-1.75 text-base',
        arrow: 'text-sm'
      },
      xl: {
        popup: 'px-4 py-2 text-lg',
        arrow: 'text-base'
      },
      '2xl': {
        popup: 'px-4.5 py-2.5 text-xl',
        arrow: 'text-lg'
      }
    }
  },
  defaultVariants: {
    size: 'md'
  }
});

import type { ThemeSize } from './types';

export const themeSizeMap: Record<ThemeSize, number> = {
  xs: 12,
  sm: 14,
  md: 16,
  lg: 18,
  xl: 20,
  '2xl': 24
};
export const miniSizeMap: Record<ThemeSize, ThemeSize> = {
  xs: 'xs',
  sm: 'xs',
  md: 'sm',
  lg: 'md',
  xl: 'lg',
  '2xl': 'xl'
};

export const themeSizeRatio = Object.fromEntries(
  Object.entries(themeSizeMap).map(([key, value]) => [key, value / themeSizeMap.md])
) as Record<ThemeSize, number>;
